import React, { useState } from 'react';
import {
  Box,
  Container,
  Typography,
  TextField,
  Button,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip
} from '@mui/material';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import EditIcon from '@mui/icons-material/Edit';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import { useTheme } from '@mui/material/styles';

const EnhancePage = () => {
  const theme = useTheme();
  const [originalText, setOriginalText] = useState('');
  const [enhancedText, setEnhancedText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isComplete, setIsComplete] = useState(false);
  const [approvalLink, setApprovalLink] = useState('');
  const [copied, setCopied] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!originalText.trim()) return;

    setIsProcessing(true);

    // Simulate API call to AI enhancement service
    setTimeout(() => {
      const enhanced = "Working with this coach transformed how I approach challenges. Their methods didn't just provide temporary solutions—they fundamentally changed my perspective. I went from feeling overwhelmed to confident and accomplished, with measurable results in just weeks.";
      setEnhancedText(enhanced);
      setIsProcessing(false);
      setIsComplete(true);
      setApprovalLink(`https://testy.app/verify/${Math.random().toString(36).substring(2, 15)}`);
    }, 2000);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(approvalLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Typography variant="h2" align="center" gutterBottom>
        Enhance Your Testimonial
      </Typography>
      <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 6 }}>
        Enter your client's original testimonial to transform it into a compelling story
      </Typography>

      {!isComplete ? (
        <Paper 
          elevation={0} 
          sx={{ 
            p: 4, 
            borderRadius: 3,
            border: '1px solid rgba(0, 0, 0, 0.08)',
            background: 'linear-gradient(to bottom, #ffffff, #f8fafc)'
          }}
        >
          <form onSubmit={handleSubmit}>
            <TextField
              label="Paste your client's testimonial"
              multiline
              rows={6}
              fullWidth
              variant="outlined"
              value={originalText}
              onChange={(e) => setOriginalText(e.target.value)}
              placeholder="Example: The coaching was good. I learned some things that helped me."
              sx={{ mb: 3 }}
            />
            <Box sx={{ display: 'flex', justifyContent: 'center' }}>
              <Button 
                type="submit"
                variant="contained"
                color="primary"
                size="large"
                disabled={isProcessing || !originalText.trim()}
                sx={{ px: 4 }}
              >
                {isProcessing ? (
                  <CircularProgress size={24} color="inherit" sx={{ mr: 1 }} />
                ) : (
                  'Enhance Testimonial'
                )}
              </Button>
            </Box>
          </form>
        </Paper>
      ) : (
        <Box>
          {/* Comparison Section */}
          <Paper 
            elevation={0} 
            sx={{ 
              p: 4, 
              borderRadius: 3,
              border: '1px solid rgba(0, 0, 0, 0.08)',
              mb: 4
            }}
          >
            <Typography variant="h5" gutterBottom>
              Compare Your Testimonials
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={12} md={6}>
                <Card sx={{ height: '100%', bgcolor: '#f8fafc' }}>
                  <CardContent>
                    <Typography variant="subtitle1" color="text.secondary" gutterBottom>
                      Original
                    </Typography>
                    <Typography variant="body1">
                      {originalText}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>

              <Grid item xs={12} md={6}>
                <Card sx={{ 
                  height: '100%', 
                  background: 'linear-gradient(135deg, #ebf3ff 0%, #f5f7ff 100%)',
                  border: '1px solid rgba(74, 144, 226, 0.3)',
                  position: 'relative'
                }}>
                  <CardContent>
                    <Typography variant="subtitle1" color="primary" gutterBottom>
                      Enhanced
                    </Typography>
                    <Typography variant="body1">
                      {enhancedText}
                    </Typography>
                    <Tooltip title="Edit">
                      <IconButton 
                        size="small" 
                        sx={{ 
                          position: 'absolute', 
                          top: 8, 
                          right: 8,
                          bgcolor: 'rgba(255, 255, 255, 0.8)'
                        }}
                      >
                        <EditIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                  </CardContent>
                </Card>
              </Grid>
            </Grid>
          </Paper>

          {/* Approval Link Section */}
          <Paper 
            elevation={0} 
            sx={{ 
              p: 4, 
              borderRadius: 3,
              border: '1px solid rgba(0, 0, 0, 0.08)',
              background: 'linear-gradient(to bottom, #ffffff, #f8fafc)'
            }}
          >
            <Typography variant="h5" gutterBottom>
              Get Client Approval
            </Typography>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
              Send this link to your client to verify this enhanced testimonial:
            </Typography>

            <Box 
              sx={{ 
                display: 'flex', 
                alignItems: 'center',
                p: 2,
                borderRadius: 1,
                border: '1px solid rgba(0, 0, 0, 0.1)',
                bgcolor: 'white',
                mb: 3
              }}
            >
              <Typography 
                variant="body2" 
                sx={{ 
                  flexGrow: 1,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap'
                }}
              >
                {approvalLink}
              </Typography>
              <Button 
                variant="outlined"
                size="small"
                onClick={handleCopy}
                startIcon={copied ? <CheckCircleIcon /> : <ContentCopyIcon />}
                sx={{ ml: 2 }}
              >
                {copied ? 'Copied!' : 'Copy Link'}
              </Button>
            </Box>

            <Alert severity="info" sx={{ mb: 4 }}>
              Your client will see both versions and can approve with one click
            </Alert>

            <Divider sx={{ my: 3 }} />

            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2, flexWrap: 'wrap' }}>
              <Button 
                variant="contained" 
                color="primary"
              >
                Download as Image
              </Button>
              <Button 
                variant="outlined"
                color="primary"
              >
                Share Testimonial
              </Button>
            </Box>
          </Paper>
        </Box>
      )}
    </Container>
  );
};

export default EnhancePage;
